"use client";

import { useState } from "react";
import { ZipEntry } from "./ZipEntry";
import { StateSelector } from "./StateSelector";
import { StateInfoCard } from "./StateInfoCard";
import { PromptOutput } from "./PromptOutput";
import { TipsSection } from "./TipsSection";
import { lookupZip } from "../../lib/zipLookup";
import { loadStateData, getNextElection } from "../../lib/stateData";
import { buildFullPrompt } from "../../lib/promptBuilder";
import type { StateData, Election } from "../../types/state";

type AppState =
  | { status: "idle" }
  | { status: "loading" }
  | { status: "multi-state"; zip: string; stateCodes: string[] }
  | { status: "not-found"; zip: string }
  | { status: "no-data"; zip: string; stateCode: string }
  | {
      status: "ready";
      zip: string;
      stateData: StateData;
      election: Election | null;
      fullPrompt: string;
    };

export function BallotTool() {
  const [appState, setAppState] = useState<AppState>({ status: "idle" });

  function handleZipSubmit(zip: string) {
    setAppState({ status: "loading" });

    // Simulated async for loading state (all data is synchronous in practice)
    const stateCodes = lookupZip(zip);

    if (!stateCodes) {
      setAppState({ status: "not-found", zip });
      return;
    }

    if (stateCodes.length > 1) {
      setAppState({ status: "multi-state", zip, stateCodes });
      return;
    }

    loadStateForCode(zip, stateCodes[0]);
  }

  function loadStateForCode(zip: string, stateCode: string) {
    const stateData = loadStateData(stateCode);

    if (!stateData) {
      setAppState({ status: "not-found", zip });
      return;
    }

    const election = getNextElection(stateData);
    const fullPrompt = buildFullPrompt(zip, stateData, election);

    setAppState({
      status: "ready",
      zip,
      stateData,
      election,
      fullPrompt,
    });
  }

  function handleStateSelect(stateCode: string) {
    if (appState.status !== "multi-state") return;
    const stateData = loadStateData(stateCode);
    if (!stateData) {
      setAppState({ status: "not-found", zip: appState.zip });
      return;
    }
    loadStateForCode(appState.zip, stateCode);
  }

  function handleReset() {
    setAppState({ status: "idle" });
  }

  return (
    <main className="w-full max-w-3xl mx-auto px-4 sm:px-6 py-8 space-y-6">
      {/* Skip-to-content target */}
      <a
        href="#main-content"
        className="sr-only focus:not-sr-only focus:absolute focus:top-4 focus:left-4 bg-white text-blue-700 px-4 py-2 rounded shadow font-medium z-50"
      >
        Skip to main content
      </a>

      {/* Hero section */}
      <header className="space-y-2">
        <h1 className="text-3xl sm:text-4xl font-extrabold text-gray-900 leading-tight">
          Free AI Ballot Research Tool
        </h1>
        <p className="text-base sm:text-lg text-gray-600 max-w-2xl">
          Enter your ZIP code to get a customized AI ballot research prompt.
          Paste it into any free AI chatbot — Claude, ChatGPT, Gemini, or Grok —
          to walk through every race and issue on your ballot.
        </p>
        <div
          className="flex flex-wrap gap-3 pt-1"
          aria-label="Supported AI chatbots"
        >
          {[
            { name: "Claude", url: "https://claude.ai" },
            { name: "ChatGPT", url: "https://chatgpt.com" },
            { name: "Gemini", url: "https://gemini.google.com" },
            { name: "Grok", url: "https://grok.com" },
          ].map((bot) => (
            <a
              key={bot.name}
              href={bot.url}
              target="_blank"
              rel="noopener noreferrer"
              className="inline-block rounded-full border border-gray-300 bg-white px-4 py-1.5 text-sm font-medium text-gray-700 hover:bg-gray-50 hover:border-gray-400 transition-colors"
            >
              {bot.name}
            </a>
          ))}
        </div>
      </header>

      {/* Main content */}
      <div id="main-content" className="space-y-6">
        {/* Zip entry — always shown */}
        <ZipEntry
          onSubmit={handleZipSubmit}
          isLoading={appState.status === "loading"}
        />

        {/* Loading */}
        {appState.status === "loading" && (
          <p className="text-gray-500 text-sm" role="status" aria-live="polite">
            Looking up your state…
          </p>
        )}

        {/* Not found */}
        {appState.status === "not-found" && (
          <div
            data-testid="not-found-message"
            role="alert"
            className="rounded-lg border border-amber-300 bg-amber-50 p-4 text-sm text-gray-800"
          >
            <p className="font-semibold mb-1">
              We don&apos;t have data for ZIP code{" "}
              <strong>{appState.zip}</strong> yet.
            </p>
            <p>
              We&apos;re working on adding all U.S. ZIP codes. In the meantime,
              visit your{" "}
              <a
                href="https://www.usa.gov/election-office"
                target="_blank"
                rel="noopener noreferrer"
                className="underline text-blue-700 hover:text-blue-900"
              >
                state election website directory
              </a>{" "}
              for official information.
            </p>
            <button
              type="button"
              onClick={handleReset}
              className="mt-3 text-blue-700 underline text-sm hover:text-blue-900 focus:outline-none"
            >
              Try a different ZIP code
            </button>
          </div>
        )}

        {/* Multi-state selector */}
        {appState.status === "multi-state" && (
          <StateSelector
            stateCodes={appState.stateCodes}
            onSelect={handleStateSelect}
          />
        )}

        {/* Ready state — show info + prompt */}
        {appState.status === "ready" && (
          <>
            <StateInfoCard
              stateData={appState.stateData}
              election={appState.election}
              zip={appState.zip}
            />
            <PromptOutput fullPromptText={appState.fullPrompt} />
            <TipsSection />
            <button
              type="button"
              onClick={handleReset}
              className="text-sm text-blue-700 underline hover:text-blue-900 focus:outline-none"
            >
              Look up a different ZIP code
            </button>
          </>
        )}
      </div>
    </main>
  );
}

export function Footer() {
  const shareText = encodeURIComponent(
    "Free tool to research your ballot with AI: ",
  );
  const shareUrl = typeof window !== "undefined" ? window.location.href : "";

  return (
    <footer className="w-full border-t border-gray-200 py-6 mt-8">
      <div className="max-w-3xl mx-auto px-4 sm:px-6 flex flex-col sm:flex-row items-center justify-between gap-4 text-sm text-gray-500">
        <div className="flex gap-4">
          <a
            href={`https://twitter.com/intent/tweet?text=${shareText}&url=${encodeURIComponent(shareUrl)}`}
            target="_blank"
            rel="noopener noreferrer"
            className="text-blue-600 hover:text-blue-800 underline font-medium"
          >
            Share this tool
          </a>
        </div>
        <p>Created by a human using AI tools</p>
      </div>
    </footer>
  );
}

"use client";

import { useState, useRef } from "react";

interface PromptOutputProps {
  fullPromptText: string;
}

export function PromptOutput({ fullPromptText }: PromptOutputProps) {
  const [copied, setCopied] = useState(false);
  const textRef = useRef<HTMLTextAreaElement>(null);

  async function handleCopy() {
    try {
      if (navigator.clipboard && navigator.clipboard.writeText) {
        await navigator.clipboard.writeText(fullPromptText);
      } else {
        // Fallback: select all text
        if (textRef.current) {
          textRef.current.select();
          document.execCommand("copy");
        }
      }
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      // Fallback: select all
      if (textRef.current) {
        textRef.current.select();
      }
    }
  }

  return (
    <section className="w-full space-y-3">
      <div className="flex items-start justify-between gap-3 flex-wrap">
        <div>
          <h2 className="text-lg font-bold text-gray-900">
            Your customized ballot research prompt
          </h2>
          <p className="text-sm text-gray-600 mt-0.5">
            Copy this prompt and paste it as your first message in any AI
            chatbot (Claude, ChatGPT, Gemini, Grok, etc.)
          </p>
        </div>
        <div className="flex items-center gap-2 shrink-0">
          <button
            data-testid="copy-button"
            type="button"
            onClick={handleCopy}
            className="flex items-center gap-2 rounded-lg bg-blue-600 text-white px-5 py-2.5 font-semibold text-sm hover:bg-blue-700 active:bg-blue-800 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 min-h-[44px]"
            aria-label="Copy prompt to clipboard"
          >
            {copied ? (
              <>
                <svg
                  className="w-4 h-4"
                  fill="none"
                  viewBox="0 0 24 24"
                  stroke="currentColor"
                  strokeWidth={2.5}
                  aria-hidden="true"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    d="M5 13l4 4L19 7"
                  />
                </svg>
                Copied!
              </>
            ) : (
              <>
                <svg
                  className="w-4 h-4"
                  fill="none"
                  viewBox="0 0 24 24"
                  stroke="currentColor"
                  strokeWidth={2}
                  aria-hidden="true"
                >
                  <rect x="9" y="9" width="13" height="13" rx="2" ry="2" />
                  <path d="M5 15H4a2 2 0 01-2-2V4a2 2 0 012-2h9a2 2 0 012 2v1" />
                </svg>
                Copy to Clipboard
              </>
            )}
          </button>
          {copied && (
            <span
              data-testid="copy-confirmation"
              role="status"
              aria-live="polite"
              className="text-sm text-green-700 font-medium"
            >
              Copied to clipboard!
            </span>
          )}
        </div>
      </div>

      <div
        data-testid="prompt-output"
        role="region"
        aria-label="Customized ballot research prompt"
        className="relative rounded-xl border border-gray-200 bg-gray-50 overflow-hidden"
      >
        <textarea
          ref={textRef}
          readOnly
          value={fullPromptText}
          rows={12}
          className="w-full bg-transparent p-4 text-sm text-gray-800 font-mono resize-y focus:outline-none focus:ring-2 focus:ring-blue-500 min-h-[200px]"
          aria-label="Ballot research prompt text"
        />
      </div>
    </section>
  );
}

"use client";

import type { StateData, Election, DeadlineInfo } from "../../types/state";
import { getDeadlineInfo, formatDate } from "../../lib/deadlineStatus";

interface StateInfoCardProps {
  stateData: StateData;
  election: Election | null;
  zip: string;
}

const statusColors: Record<string, string> = {
  green: "text-green-700 bg-green-50 border-green-200",
  yellow: "text-amber-700 bg-amber-50 border-amber-200",
  red: "text-red-700 bg-red-50 border-red-200",
  passed: "text-gray-500 bg-gray-50 border-gray-200",
};

function DeadlineBadge({ info, label }: { info: DeadlineInfo; label: string }) {
  return (
    <div
      className={`rounded border px-3 py-2 text-sm ${statusColors[info.status]}`}
    >
      <span className="font-medium">{label}:</span>{" "}
      {info.date ? formatDate(info.date) : "N/A"}{" "}
      <span className="font-semibold">({info.label})</span>
    </div>
  );
}

function ElectionBlock({
  election,
  stateData,
}: {
  election: Election | null;
  stateData: StateData;
}) {
  if (!election) {
    return (
      <p data-testid="no-election-message" className="text-gray-700">
        No upcoming elections found for {stateData.stateName}. Check{" "}
        <a
          href={stateData.resources.stateElectionWebsite}
          target="_blank"
          rel="noopener noreferrer"
          className="underline text-blue-700 hover:text-blue-900"
        >
          {stateData.stateName} election website
        </a>{" "}
        for updates.
      </p>
    );
  }
  return (
    <div className="space-y-1">
      <div className="flex items-center gap-2 flex-wrap">
        <span className="font-semibold text-gray-800">Next election:</span>
        <span data-testid="election-name" className="text-gray-900">
          {election.name}
        </span>
      </div>
      <div className="flex items-center gap-2 flex-wrap">
        <span className="font-semibold text-gray-800">Date:</span>
        <span data-testid="election-date" className="text-gray-900">
          {formatDate(election.date)}
        </span>
        {election.primaryType && (
          <span className="text-sm text-gray-600 capitalize">
            ({election.primaryType} primary)
          </span>
        )}
      </div>
    </div>
  );
}

function RegistrationBlock({ stateData }: { stateData: StateData }) {
  const today = new Date();
  const reg = stateData.registration;
  const onlineDeadline =
    reg.online.available && reg.online.deadline
      ? getDeadlineInfo(reg.online.deadline, today)
      : null;
  const mailDeadline = getDeadlineInfo(reg.byMail.deadline, today);
  const inPersonDeadline = getDeadlineInfo(reg.inPerson.deadline, today);

  return (
    <div data-testid="registration-status" className="space-y-2">
      <h3 className="font-semibold text-gray-800">Registration deadlines</h3>
      <div className="grid gap-2 sm:grid-cols-2 lg:grid-cols-3">
        {onlineDeadline && (
          <DeadlineBadge info={onlineDeadline} label="Online" />
        )}
        {!reg.online.available && (
          <div className="rounded border px-3 py-2 text-sm text-gray-500 bg-gray-50 border-gray-200">
            <span className="font-medium">Online:</span> Not available
          </div>
        )}
        <DeadlineBadge
          info={mailDeadline}
          label={`By mail${reg.byMail.sincePostmarked ? " (postmark)" : ""}`}
        />
        <DeadlineBadge info={inPersonDeadline} label="In person" />
      </div>
      {reg.sameDayRegistration && (
        <p className="text-sm text-green-700 font-medium">
          Same-day registration available
        </p>
      )}
      <a
        href={reg.registrationCheckUrl}
        target="_blank"
        rel="noopener noreferrer"
        className="inline-block text-sm text-blue-700 underline hover:text-blue-900"
      >
        Check your registration status
      </a>
    </div>
  );
}

export function StateInfoCard({
  stateData,
  election,
  zip,
}: StateInfoCardProps) {
  return (
    <section
      data-testid="state-info"
      className="w-full rounded-xl border border-blue-200 bg-blue-50 p-5 space-y-4"
      aria-label={`Election information for ${stateData.stateName}`}
    >
      <div className="flex items-center gap-2">
        <h2 className="text-xl font-bold text-gray-900">
          {stateData.stateName}
        </h2>
        <span className="text-sm text-gray-500">ZIP {zip}</span>
      </div>

      <ElectionBlock election={election} stateData={stateData} />
      <RegistrationBlock stateData={stateData} />

      {stateData.earlyVoting.available &&
        stateData.earlyVoting.startDate &&
        stateData.earlyVoting.endDate && (
          <div>
            <h3 className="font-semibold text-gray-800 mb-1">Early voting</h3>
            <p className="text-sm text-gray-700">
              {formatDate(stateData.earlyVoting.startDate)} through{" "}
              {formatDate(stateData.earlyVoting.endDate)}
              {stateData.earlyVoting.notes && (
                <span className="text-gray-500">
                  {" "}
                  &mdash; {stateData.earlyVoting.notes}
                </span>
              )}
            </p>
          </div>
        )}

      <div className="grid gap-3 sm:grid-cols-2">
        <div>
          <h3 className="font-semibold text-gray-800 mb-1">Voter ID</h3>
          <p className="text-sm text-gray-700">
            {stateData.votingRules.idRequired ? "Required" : "Not required"}
          </p>
        </div>
        <div>
          <h3 className="font-semibold text-gray-800 mb-1">Phones at polls</h3>
          <p className="text-sm text-gray-700 capitalize">
            {stateData.votingRules.phonesAtPolls}
          </p>
        </div>
      </div>

      <div className="flex gap-4 flex-wrap text-sm">
        <a
          href={stateData.resources.stateElectionWebsite}
          target="_blank"
          rel="noopener noreferrer"
          className="text-blue-700 underline hover:text-blue-900"
        >
          State election website
        </a>
        <a
          href={stateData.resources.sampleBallotLookup}
          target="_blank"
          rel="noopener noreferrer"
          className="text-blue-700 underline hover:text-blue-900"
        >
          Sample ballot lookup
        </a>
        <a
          href={stateData.resources.countyElectionLookup}
          target="_blank"
          rel="noopener noreferrer"
          className="text-blue-700 underline hover:text-blue-900"
        >
          County election office
        </a>
      </div>
    </section>
  );
}

"use client";

import { useState, KeyboardEvent } from "react";

interface ZipEntryProps {
  onSubmit: (zip: string) => void;
  isLoading?: boolean;
}

export function ZipEntry({ onSubmit, isLoading = false }: ZipEntryProps) {
  const [zip, setZip] = useState("");
  const [error, setError] = useState<string | null>(null);

  function validate(value: string): string | null {
    if (!value.trim()) return "Please enter a zip code";
    if (!/^\d{5}$/.test(value.trim()))
      return "Please enter a valid 5-digit zip code";
    return null;
  }

  function handleSubmit() {
    const trimmed = zip.trim();
    const err = validate(trimmed);
    if (err) {
      setError(err);
      return;
    }
    setError(null);
    onSubmit(trimmed);
  }

  function handleKeyDown(e: KeyboardEvent<HTMLInputElement>) {
    if (e.key === "Enter") handleSubmit();
  }

  function handleChange(value: string) {
    setZip(value);
    if (error) {
      const err = validate(value.trim());
      if (!err) setError(null);
    }
  }

  return (
    <div className="w-full">
      <label
        htmlFor="zip-input"
        className="block text-sm font-medium text-gray-700 mb-1"
      >
        Enter your ZIP code
      </label>
      <div className="flex gap-2 flex-wrap sm:flex-nowrap">
        <input
          id="zip-input"
          data-testid="zip-input"
          type="text"
          inputMode="numeric"
          pattern="[0-9]*"
          maxLength={5}
          value={zip}
          onChange={(e) => handleChange(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="e.g. 73301"
          aria-describedby={error ? "zip-error" : undefined}
          aria-invalid={!!error}
          className="flex-1 min-w-0 rounded-lg border border-gray-300 px-4 py-3 text-base focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500 min-h-[44px]"
          disabled={isLoading}
        />
        <button
          data-testid="zip-submit"
          type="button"
          onClick={handleSubmit}
          disabled={isLoading}
          className="rounded-lg bg-blue-600 text-white px-6 py-3 font-semibold text-base hover:bg-blue-700 active:bg-blue-800 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 disabled:opacity-50 min-h-[44px] min-w-[120px] whitespace-nowrap"
        >
          {isLoading ? "Looking up…" : "Look up my ballot"}
        </button>
      </div>
      {error && (
        <p
          id="zip-error"
          data-testid="zip-error"
          role="alert"
          aria-live="polite"
          className="mt-2 text-sm text-red-600"
        >
          {error}
        </p>
      )}
    </div>
  );
}

import type { DeadlineInfo } from "../types/state";

export function getDeadlineInfo(
  deadline: string | null,
  today: Date = new Date(),
): DeadlineInfo {
  if (!deadline) {
    return {
      date: null,
      status: "passed",
      daysRemaining: null,
      label: "Not available",
    };
  }

  // Parse both dates as UTC to avoid timezone issues
  const deadlineDate = new Date(deadline + "T00:00:00Z");
  const todayUTC = new Date(
    Date.UTC(today.getUTCFullYear(), today.getUTCMonth(), today.getUTCDate()),
  );
  const msPerDay = 1000 * 60 * 60 * 24;
  const daysRemaining = Math.round(
    (deadlineDate.getTime() - todayUTC.getTime()) / msPerDay,
  );

  if (daysRemaining < 0) {
    return {
      date: deadline,
      status: "passed",
      daysRemaining: null,
      label: "Passed",
    };
  }

  if (daysRemaining === 0) {
    return { date: deadline, status: "red", daysRemaining: 0, label: "Today" };
  }

  if (daysRemaining <= 3) {
    return {
      date: deadline,
      status: "red",
      daysRemaining,
      label: `${daysRemaining} day${daysRemaining === 1 ? "" : "s"} left`,
    };
  }

  if (daysRemaining <= 14) {
    return {
      date: deadline,
      status: "yellow",
      daysRemaining,
      label: `${daysRemaining} days left`,
    };
  }

  return {
    date: deadline,
    status: "green",
    daysRemaining,
    label: `${daysRemaining} days left`,
  };
}

export function formatDate(isoDate: string): string {
  const d = new Date(isoDate + "T00:00:00Z");
  return d.toLocaleDateString("en-US", {
    month: "long",
    day: "numeric",
    year: "numeric",
    timeZone: "UTC",
  });
}

import type { StateData, Election } from "../types/state";
import { formatDate, getDeadlineInfo } from "./deadlineStatus";
import { BALLOT_PROMPT_TEXT } from "./ballotPromptText";

function buildElectionLine(election: Election | null): string {
  if (!election) return "- **Election:** No upcoming election found";
  const typeSuffix = election.primaryType
    ? ` (${election.primaryType} primary)`
    : "";
  return `- **Election:** ${election.name} on ${formatDate(election.date)}\n- **Election type:** ${election.type}${typeSuffix}`;
}

function buildRegistrationLine(state: StateData): string {
  const reg = state.registration;
  const today = new Date();
  const onlineDeadline =
    reg.online.available && reg.online.deadline
      ? getDeadlineInfo(reg.online.deadline, today)
      : null;
  const mailDeadline = getDeadlineInfo(reg.byMail.deadline, today);
  const inPersonDeadline = getDeadlineInfo(reg.inPerson.deadline, today);

  const onlinePart =
    reg.online.available && reg.online.deadline
      ? `Online by ${formatDate(reg.online.deadline)} (${onlineDeadline?.label})`
      : "Online: Not available";
  const mailDate = reg.byMail.deadline
    ? formatDate(reg.byMail.deadline)
    : "N/A";
  const mailPostmark = reg.byMail.sincePostmarked ? " — postmark date" : "";
  const inPersonDate = reg.inPerson.deadline
    ? formatDate(reg.inPerson.deadline)
    : "N/A";

  return `- **Registration deadlines:** ${onlinePart}; By mail by ${mailDate} (${mailDeadline.label}${mailPostmark}); In person by ${inPersonDate} (${inPersonDeadline.label})`;
}

function buildEarlyVotingLine(state: StateData): string {
  const ev = state.earlyVoting;
  if (ev.available && ev.startDate && ev.endDate) {
    return `- **Early voting:** ${formatDate(ev.startDate)} through ${formatDate(ev.endDate)}`;
  }
  return "- **Early voting:** Not available — absentee voting only";
}

function buildIdLine(state: StateData): string {
  if (!state.votingRules.idRequired) return "- **Voter ID:** Not required";
  const ids = state.votingRules.acceptedIds;
  const idList =
    ids.slice(0, 3).join(", ") + (ids.length > 3 ? ", and others" : "");
  return `- **Voter ID:** Required. Accepted: ${idList}`;
}

export function buildContextBlock(
  zip: string,
  state: StateData,
  election: Election | null,
): string {
  return `Hi! I'm voting in **${state.stateName}**. My zip code is **${zip}**.

Here's what I know about my upcoming election:
${buildElectionLine(election)}
${buildRegistrationLine(state)}
${buildEarlyVotingLine(state)}
${buildIdLine(state)}
